queries.sparql:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?technique_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasResearch_Techniques ?child ; p:hasProjects ?parent . } GROUP BY ?child }
  ?child p:technique_name ?technique_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Projects } }
  FILTER(?nf = ?total)
}

