CHOICE scope {
  collective: { SELECT ?technique_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasResearch_Techniques ?child ; p:hasProjects ?parent . } GROUP BY ?child }
  ?child p:technique_name ?technique_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Projects } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?project_name ?technique_name WHERE {
  ?projects_research_techniques a :Projects_Research_Techniques .
  ?research_techniques a :Research_Techniques .
  ?projects_research_techniques p:hasResearch_Techniques ?research_techniques .
  ?projects a :Projects .
  ?projects_research_techniques p:hasProjects ?projects .
  ?projects p:project_name ?project_name .
  ?research_techniques p:technique_name ?technique_name .
} }
}

